    super().__init__()
    self.prob = prob

def forward(self, x):
    device = x.device

    if self.prob == 0. or (not self.training):
        return x

    keep_mask = torch.FloatTensor((x.shape[0], 1, 1, 1), device = device).uniform_() > self.prob
    return x * keep_mask / (1 - self.prob)

def forward(self, x):
